(function () {
  function addStyle(){ if(document.getElementById('rsa-style'))return; var s=document.createElement('style'); s.id='rsa-style'; s.textContent='.rsa-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.rsa-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px}.rsa-card{background:#f8fafc;border:1px solid #e5e7eb;border-radius:10px;padding:12px}.rsa-out{padding:10px;border-radius:8px;background:#e8f4fd;border-left:4px solid #007bff;line-height:1.7;margin-top:10px}.rsa-actions{display:flex;gap:8px;flex-wrap:wrap;margin-top:10px}'; document.head.appendChild(s); }
  function mount(host){ if(!host||host.dataset.rsaMounted)return; host.dataset.rsaMounted='1'; addStyle(); host.innerHTML='<div class="rsa-wrap"><h4>🔐 Mô phỏng RSA nhỏ</h4><div class="rsa-grid"><div class="rsa-card">p=3, q=11<br>n=pq=<strong>33</strong><br>φ(n)=20</div><div class="rsa-card">Khóa công khai: (e,n)=(7,33)<br>Khóa riêng: d=3<br>Vì 7·3 ≡ 1 (mod 20)</div><label class="rsa-card">Thông điệp m (0-32)<input data-m type="number" min="0" max="32" value="5"></label></div><div class="rsa-actions"><button type="button" data-enc>Mã hóa</button><button type="button" data-dec>Giải mã</button></div><div class="rsa-out"></div></div>'; var last=0,out=host.querySelector('.rsa-out'); function modPow(a,e,n){var r=1; a%=n; while(e){if(e&1)r=r*a%n; a=a*a%n; e=Math.floor(e/2);} return r;} host.querySelector('[data-enc]').onclick=function(){var m=Math.max(0,Math.min(32,+host.querySelector('[data-m]').value||0)); last=modPow(m,7,33); out.innerHTML='Mã hóa: c = m<sup>e</sup> mod n = '+m+'<sup>7</sup> mod 33 = <strong>'+last+'</strong><br>Euler: nếu gcd(m,33)=1 thì m<sup>20</sup> ≡ 1 (mod 33), nên e·d=21 giúp giải mã quay về m.';}; host.querySelector('[data-dec]').onclick=function(){var m=modPow(last,3,33); out.innerHTML='Giải mã: m = c<sup>d</sup> mod n = '+last+'<sup>3</sup> mod 33 = <strong>'+m+'</strong><br>Thông điệp phục hồi là '+m+'.';}; host.querySelector('[data-enc]').click(); }
  document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('[data-demo="rsa-simulator"]').forEach(mount);});
}());
